const frame = context.panel.data.series.find((series) => series.refId === 'A') || context.panel.data.series[0];

const getValues = (name) => {
  const field = frame?.fields.find((item) => item.name === name);
  const values = field?.values;
  if (!values) {
    return [];
  }
  if (Array.isArray(values)) {
    return values;
  }
  if (values.toArray) {
    return values.toArray();
  }
  if (values.buffer) {
    return Array.from(values.buffer);
  }
  return Array.from(values);
};

const symbols = getValues('symbol');
const rows = symbols.map((_, index) => ({
  symbol: getValues('symbol')[index],
  base: getValues('base_asset')[index],
  rsi: Number(getValues('rsi')[index]),
  prevRsi: Number(getValues('prev_rsi')[index]),
  delta: Number(getValues('rsi_delta')[index]),
  zone: getValues('zone')[index],
  volume: Number(getValues('quote_volume_24h')[index]),
  change: Number(getValues('price_change_pct')[index]),
  close: Number(getValues('latest_close')[index]),
  time: getValues('latest_time')[index],
})).filter((row) => Number.isFinite(row.rsi) && Number.isFinite(row.volume) && row.volume > 0);

const zoneColors = {
  Overbought: '#ef4444',
  Strong: '#9f2f3f',
  Neutral: '#9ca3af',
  Weak: '#34d399',
  Oversold: '#14b8a6',
};

const formatUsd = (value) => {
  if (!Number.isFinite(Number(value))) {
    return '-';
  }
  const number = Number(value);
  if (number >= 1e12) return `$${(number / 1e12).toFixed(number >= 10e12 ? 0 : 1)}T`;
  if (number >= 1e9) return `$${(number / 1e9).toFixed(number >= 10e9 ? 0 : 1)}B`;
  if (number >= 1e6) return `$${(number / 1e6).toFixed(number >= 10e6 ? 0 : 1)}M`;
  if (number >= 1e3) return `$${(number / 1e3).toFixed(0)}K`;
  return `$${number.toFixed(0)}`;
};

const formatPrice = (value) => {
  if (!Number.isFinite(Number(value))) {
    return '-';
  }
  const number = Number(value);
  if (number >= 1000) return `$${number.toLocaleString(undefined, { maximumFractionDigits: 2 })}`;
  if (number >= 1) return `$${number.toFixed(2)}`;
  if (number >= 0.01) return `$${number.toFixed(4)}`;
  return `$${number.toPrecision(4)}`;
};

const pointData = (zone) => rows
  .filter((row) => row.zone === zone)
  .map((row) => ({
    name: row.base,
    value: [row.volume, row.rsi, row.prevRsi, row.base, row.symbol, row.zone, row.delta, row.change, row.close, row.time],
    itemStyle: { color: zoneColors[row.zone] },
  }));

const zoneSeries = Object.keys(zoneColors).map((zone) => ({
  name: zone,
  type: 'scatter',
  data: pointData(zone),
  symbolSize: 12,
  itemStyle: {
    color: zoneColors[zone],
  },
  label: {
    show: true,
    formatter: '{@[3]}',
    position: 'top',
    color: '#e5e7eb',
    fontSize: 11,
    fontWeight: 600,
  },
  emphasis: {
    focus: 'series',
    label: {
      show: true,
      fontSize: 13,
    },
  },
  tooltip: {
    trigger: 'item',
  },
}));

return {
  backgroundColor: 'transparent',
  color: Object.values(zoneColors),
  grid: {
    left: 58,
    right: 44,
    top: 52,
    bottom: 52,
  },
  legend: {
    top: 8,
    icon: 'circle',
    left: 'center',
    itemWidth: 10,
    itemHeight: 10,
    data: Object.keys(zoneColors),
    textStyle: {
      color: '#d1d5db',
      fontSize: 11,
    },
  },
  tooltip: {
    trigger: 'item',
    confine: true,
    backgroundColor: 'rgba(17, 24, 39, 0.96)',
    borderColor: '#374151',
    textStyle: { color: '#f9fafb' },
    formatter: (params) => {
      const value = params.value || [];
      const delta = Number(value[6]);
      const deltaText = Number.isFinite(delta) ? `${delta >= 0 ? '+' : ''}${delta.toFixed(2)}` : '-';
      const change = Number(value[7]);
      const changeText = Number.isFinite(change) ? `${change >= 0 ? '+' : ''}${change.toFixed(2)}%` : '-';
      const close = Number(value[8]);
      const closeText = Number.isFinite(close) ? formatPrice(close) : '-';
      return [
        `<b>${value[3]} (${value[4]})</b>`,
        `Zone: ${value[5]}`,
        `RSI: ${Number(value[1]).toFixed(2)} (${deltaText})`,
        `Prev RSI: ${Number(value[2]).toFixed(2)}`,
        `24h Volume: ${formatUsd(value[0])}`,
        `24h Change: ${changeText}`,
        `Latest Close: ${closeText}`,
        `Latest Time: ${value[9]}`,
      ].join('<br/>');
    },
  },
  xAxis: {
    type: 'log',
    inverse: true,
    name: '24h Quote Volume (USDT)',
    nameLocation: 'middle',
    nameGap: 34,
    splitLine: {
      lineStyle: { color: 'rgba(156, 163, 175, 0.28)', type: 'dotted' },
    },
    axisLabel: {
      color: '#9ca3af',
      formatter: formatUsd,
    },
    axisLine: { lineStyle: { color: '#4b5563' } },
  },
  yAxis: {
    type: 'value',
    min: 10,
    max: 90,
    name: 'Relative Strength Index',
    nameLocation: 'middle',
    nameGap: 42,
    splitLine: {
      lineStyle: { color: 'rgba(156, 163, 175, 0.28)', type: 'dotted' },
    },
    axisLabel: { color: '#9ca3af' },
    axisLine: { lineStyle: { color: '#4b5563' } },
  },
  series: [
    {
      name: 'RSI Bands',
      type: 'scatter',
      data: [],
      silent: true,
      markArea: {
        silent: true,
        itemStyle: { opacity: 0.24 },
        label: { color: '#cbd5e1', fontSize: 16, position: 'insideRight' },
        data: [
          [{ yAxis: 70, itemStyle: { color: '#7f1d1d' }, label: { formatter: 'OVERBOUGHT' } }, { yAxis: 90 }],
          [{ yAxis: 60, itemStyle: { color: '#4c1d2b' }, label: { formatter: 'STRONG' } }, { yAxis: 70 }],
          [{ yAxis: 40, itemStyle: { color: '#1f2937' }, label: { formatter: 'NEUTRAL' } }, { yAxis: 60 }],
          [{ yAxis: 30, itemStyle: { color: '#064e3b' }, label: { formatter: 'WEAK' } }, { yAxis: 40 }],
          [{ yAxis: 10, itemStyle: { color: '#115e59' }, label: { formatter: 'OVERSOLD' } }, { yAxis: 30 }],
        ],
      },
      tooltip: { show: false },
    },
    {
      name: 'RSI Change',
      type: 'custom',
      silent: true,
      data: rows.map((row) => [row.volume, row.prevRsi, row.rsi, row.delta >= 0 ? '#14b8a6' : '#ef4444']),
      renderItem: (params, api) => {
        const start = api.coord([api.value(0), api.value(1)]);
        const end = api.coord([api.value(0), api.value(2)]);
        return {
          type: 'line',
          shape: { x1: start[0], y1: start[1], x2: end[0], y2: end[1] },
          style: { stroke: api.value(3), lineDash: [3, 3], lineWidth: 1, opacity: 0.65 },
        };
      },
      tooltip: { show: false },
    },
    ...zoneSeries,
  ],
};

